import { openDB } from "idb";
const DB_NAME = "openbrowser-chat";
const DB_VERSION = 1;
let dbInstance = null;
// Initialize database
export async function initDB() {
    if (dbInstance) {
        return dbInstance;
    }
    dbInstance = await openDB(DB_NAME, DB_VERSION, {
        upgrade(db) {
            // Create sessions store
            if (!db.objectStoreNames.contains("sessions")) {
                const sessionStore = db.createObjectStore("sessions", {
                    keyPath: "id"
                });
                sessionStore.createIndex("by-updated", "updatedAt");
            }
            // Create messages store
            if (!db.objectStoreNames.contains("messages")) {
                const messageStore = db.createObjectStore("messages", {
                    keyPath: "id"
                });
                messageStore.createIndex("by-session", "sessionId");
            }
        }
    });
    return dbInstance;
}
// Session operations
export async function createSession(id, title) {
    const db = await initDB();
    const now = Date.now();
    await db.add("sessions", {
        id,
        title,
        createdAt: now,
        updatedAt: now
    });
}
export async function getSession(id) {
    const db = await initDB();
    return await db.get("sessions", id);
}
export async function deleteSession(id) {
    const db = await initDB();
    await db.delete("sessions", id);
}
export async function updateSessionTitle(id, title) {
    const db = await initDB();
    const session = await db.get("sessions", id);
    if (!session) {
        throw new Error(`Session ${id} not found`);
    }
    session.title = title;
    await db.put("sessions", session);
}
export async function updateSessionTimestamp(id) {
    const db = await initDB();
    const session = await db.get("sessions", id);
    if (!session) {
        throw new Error(`Session ${id} not found`);
    }
    session.updatedAt = Date.now();
    await db.put("sessions", session);
}
export async function listSessions() {
    const db = await initDB();
    return await db.getAllFromIndex("sessions", "by-updated");
}
// Message operations
export async function saveMessages(sessionId, messages) {
    const db = await initDB();
    const tx = db.transaction("messages", "readwrite");
    for (const message of messages) {
        await tx.store.put({
            id: message.id,
            sessionId,
            message
        });
    }
    await tx.done;
}
export async function loadMessages(sessionId) {
    const db = await initDB();
    const records = await db.getAllFromIndex("messages", "by-session", sessionId);
    return records.map((record) => record.message);
}
export async function clearMessagesForSession(sessionId) {
    const db = await initDB();
    const records = await db.getAllFromIndex("messages", "by-session", sessionId);
    const tx = db.transaction("messages", "readwrite");
    for (const record of records) {
        await tx.store.delete(record.id);
    }
    await tx.done;
}
